import asyncio
import json
import websockets
import time
from collections import defaultdict
from dataclasses import dataclass
from typing import Dict, List, Set
import math

@dataclass
class Position:
    x: float
    y: float
    z: float

@dataclass
class Player:
    id: str
    position: Position
    health: int
    team: str
    is_alive: bool

class BattleRoyaleServer:
    def __init__(self):
        self.players: Dict[str, Player] = {}
        self.connections: Dict[str, websockets.WebSocketServerProtocol] = {}
        self.game_state = {
            'players': {},
            'timestamp': 0,
            'game_time': 0
        }
        self.broadcast_interval = 0.1  # 100ms
        self.last_broadcast = 0

    async def register_player(self, websocket, player_id: str):
        self.connections[player_id] = websocket
        print(f"Player {player_id} connected")
        await self.send_initial_state(player_id)

    async def unregister_player(self, player_id: str):
        if player_id in self.connections:
            del self.connections[player_id]
        if player_id in self.players:
            del self.players[player_id]
        print(f"Player {player_id} disconnected")

    async def send_initial_state(self, player_id: str):
        await self.connections[player_id].send(json.dumps({
            'type': 'initial_state',
            'game_state': self.game_state,
            'player_id': player_id
        }))

    async def update_player_position(self, player_id: str, position: Position):
        if player_id in self.players:
            self.players[player_id].position = position
            self.game_state['players'][player_id] = {
                'id': player_id,
                'position': {
                    'x': position.x,
                    'y': position.y,
                    'z': position.z
                },
                'health': self.players[player_id].health,
                'team': self.players[player_id].team,
                'is_alive': self.players[player_id].is_alive
            }

    async def broadcast_game_state(self):
        current_time = time.time()
        if current_time - self.last_broadcast >= self.broadcast_interval:
            self.game_state['timestamp'] = current_time
            self.game_state['game_time'] = current_time
            
            # Send to all connected players
            for player_id, websocket in self.connections.items():
                try:
                    await websocket.send(json.dumps({
                        'type': 'game_state',
                        'game_state': self.game_state
                    }))
                except:
                    pass
            
            self.last_broadcast = current_time

    async def handle_client_message(self, websocket, message: str, player_id: str):
        data = json.loads(message)
        if data['type'] == 'position_update':
            position = Position(
                data['position']['x'],
                data['position']['y'],
                data['position']['z']
            )
            await self.update_player_position(player_id, position)
        elif data['type'] == 'player_join':
            self.players[player_id] = Player(
                id=player_id,
                position=Position(0, 0, 0),
                health=100,
                team=data.get('team', 'spectator'),
                is_alive=True
            )
            await self.send_initial_state(player_id)

    async def handle_connection(self, websocket, path):
        player_id = None
        try:
            async for message in websocket:
                if not player_id:
                    data = json.loads(message)
                    if data['type'] == 'join_game':
                        player_id = data['player_id']
                        await self.register_player(websocket, player_id)
                else:
                    await self.handle_client_message(websocket, message, player_id)
        except websockets.exceptions.ConnectionClosed:
            pass
        finally:
            if player_id:
                await self.unregister_player(player_id)

    async def run(self, host='localhost', port=8765):
        server = await websockets.serve(self.handle_connection, host, port)
        print(f"Battle Royale Server running on {host}:{port}")
        
        # Start broadcasting loop
        while True:
            await self.broadcast_game_state()
            await asyncio.sleep(0.05)

# Create and start server
if __name__ == "__main__":
    server = BattleRoyaleServer()
    asyncio.run(server.run())